"""
ROI Blink Overlay — Python / Suite2p edition
=============================================
GUI for rendering Suite2p ROIs as blinking overlays on a mean projection.

Inputs
------
  stat.npy        Suite2p stat file  (list of dicts with ypix / xpix)
  iscell.npy      Suite2p iscell     [N x 2], col-0 is 0/1 flag
  ops.npy         Suite2p ops        dict with 'meanImg' and 'fs'
  spiketimes.npy  Spike times in seconds, one of:
                    - object array of 1-D arrays  (one per unit)
                    - 2-D float array  [units x max_spikes], NaN-padded
                    - structured/dict array with field 'spiketimes' or 'spks'

Dependencies
------------
  numpy, scipy, Pillow, imageio[ffmpeg], scikit-image, tkinter (stdlib)

Install:
  pip install numpy scipy Pillow imageio[ffmpeg] scikit-image imageio-ffmpeg
"""

import tkinter as tk
from tkinter import ttk, filedialog, messagebox
import threading
import queue
import os
import time
from pathlib import Path

import numpy as np
from scipy.signal import fftconvolve
from PIL import Image, ImageTk
import imageio


# ── Rendering engine (pure numpy, no GUI deps) ────────────────────────────────

def build_kernel(tau_rise: float, tau_decay: float, fps: float) -> np.ndarray:
    dt   = 1.0 / fps
    tmax = 5 * max(tau_rise, tau_decay)
    t    = np.arange(0, tmax + dt, dt)
    kern = np.exp(-t / tau_decay) - np.exp(-t / tau_rise)
    kern = np.clip(kern, 0, None)
    if kern.max() > 0:
        kern /= kern.max()
    return kern.astype(np.float32)


def load_spiketimes(path: str) -> list:
    """
    Load spiketimes from a .npy or .mat file.
    Returns a list of 1-D numpy arrays (one per unit), times in seconds.

    .npy handles:
      - object array of arrays
      - 2-D float array (NaN-padded rows)
      - dict with 'spiketimes' / 'spks' / 'spike_times' key

    .mat handles:
      - v5/v6/v7 .mat via scipy.io.loadmat
      - v7.3 HDF5 .mat via h5py
      - searches up to 3 levels deep for a spiketimes field
    """
    ext = Path(path).suffix.lower()
    if ext == '.mat':
        return _load_spiketimes_mat(path)
    else:
        return _load_spiketimes_npy(path)


def _load_spiketimes_npy(path: str) -> list:
    raw = np.load(path, allow_pickle=True)

    if raw.ndim == 0:
        raw = raw.item()

    if isinstance(raw, dict):
        for key in ('spiketimes', 'spks', 'spike_times', 'spikeTimes', 't'):
            if key in raw:
                raw = raw[key]
                break
        else:
            raise ValueError(f"Dict in {path} has no spiketimes key. "
                             f"Keys found: {list(raw.keys())}")

    raw = np.asarray(raw, dtype=object) if raw.dtype == object else raw

    if raw.dtype == object:
        return [np.asarray(raw[i], dtype=np.float32).ravel()
                for i in range(len(raw))]

    if raw.ndim == 2:
        result = []
        for row in raw:
            st = row[~np.isnan(row)]
            result.append(st.astype(np.float32))
        return result

    if raw.ndim == 1:
        return [raw.astype(np.float32)]

    raise ValueError(f"Cannot parse spiketimes from {path} — shape {raw.shape}")


# Aliases searched at every level of a .mat struct
_SPIKE_ALIASES = ('spiketimes', 'spks', 'spike_times', 'spikeTimes',
                  't_spikes', 't', 'times', 'ST')


def _load_spiketimes_mat(path: str) -> list:
    """Load spiketimes from a .mat file (v5 or v7.3 HDF5)."""
    scipy_err = None
    h5_err    = None

    # Try scipy first (covers v5 / v6 / v7)
    try:
        from scipy.io import loadmat
        data = loadmat(path, squeeze_me=True, struct_as_record=False)
        data = {k: v for k, v in data.items() if not k.startswith('_')}
        val, path_str = _mat_search(data, max_depth=3)
        if val is not None:
            return _mat_value_to_list(val, path_str)
    except Exception as e:
        scipy_err = e

    # Try h5py for v7.3
    try:
        import h5py
        with h5py.File(path, 'r') as f:
            val, path_str = _h5_search(f, max_depth=3)
            if val is not None:
                # _h5_deref may already return a list (dereferenced cell array)
                if isinstance(val, list):
                    return val
                return _mat_value_to_list(val, path_str)
    except Exception as e:
        h5_err = e

    if scipy_err and h5_err:
        raise ValueError(
            f"Could not read {path} as v5 .mat or v7.3 HDF5.\n"
            f"scipy error: {scipy_err}\nh5py error: {h5_err}"
        )

    # Both loaders opened the file but found no spiketimes field
    try:
        from scipy.io import loadmat
        data = loadmat(path, squeeze_me=True, struct_as_record=False)
        keys = [k for k in data if not k.startswith('_')]
    except Exception:
        keys = []
    raise ValueError(
        f"Could not find spiketimes in {path}.\n"
        f"Searched aliases: {_SPIKE_ALIASES}\n"
        f"Top-level keys found: {keys}"
    )


def _mat_search(node, depth=0, max_depth=3, path=''):
    """Recursively search a scipy loadmat dict/struct for a spiketimes field."""
    import scipy.io
    if depth > max_depth:
        return None, ''

    if isinstance(node, dict):
        keys = node.keys()
    elif hasattr(node, '_fieldnames'):       # MATLAB struct from loadmat
        keys = node._fieldnames
    else:
        return None, ''

    # Check this level first
    for alias in _SPIKE_ALIASES:
        for k in keys:
            if k.lower() == alias.lower():
                val = node[k] if isinstance(node, dict) else getattr(node, k)
                return val, f'{path}.{k}' if path else k

    # Recurse one level deeper
    for k in keys:
        val = node[k] if isinstance(node, dict) else getattr(node, k)
        if isinstance(val, dict) or hasattr(val, '_fieldnames'):
            found, fpath = _mat_search(val, depth+1, max_depth,
                                       f'{path}.{k}' if path else k)
            if found is not None:
                return found, fpath
        # Also handle arrays of structs
        if hasattr(val, 'flat'):
            for item in val.flat:
                if hasattr(item, '_fieldnames'):
                    found, fpath = _mat_search(item, depth+1, max_depth,
                                               f'{path}.{k}[]' if path else f'{k}[]')
                    if found is not None:
                        return found, fpath

    return None, ''


def _h5_search(node, depth=0, max_depth=3, path='', h5file=None):
    """Recursively search an h5py group for a spiketimes dataset."""
    import h5py
    if depth > max_depth:
        return None, ''
    if not isinstance(node, (h5py.File, h5py.Group)):
        return None, ''

    # Keep a reference to the root file for dereferencing
    if h5file is None:
        h5file = node.file if hasattr(node, 'file') else node

    for alias in _SPIKE_ALIASES:
        for k in node.keys():
            if k.lower() == alias.lower():
                val = _h5_deref(node[k], h5file)
                return val, f'{path}/{k}' if path else k

    for k in node.keys():
        if k == '#refs#':
            continue
        child = node[k]
        if isinstance(child, h5py.Group):
            found, fpath = _h5_search(child, depth+1, max_depth,
                                      f'{path}/{k}' if path else k,
                                      h5file)
            if found is not None:
                return found, fpath

    return None, ''


def _h5_deref(item, h5file):
    """
    Read an h5py Dataset or Group, dereferencing object references
    (MATLAB cell arrays stored as ref arrays) if needed.
    Returns a list of 1-D float32 arrays or a raw numpy array.
    """
    import h5py

    # If it's a Group it might be a MATLAB struct — recurse into it
    if isinstance(item, h5py.Group):
        for alias in _SPIKE_ALIASES:
            for k in item.keys():
                if k.lower() == alias.lower():
                    return _h5_deref(item[k], h5file)
        return None

    # It's a Dataset — read it
    raw = item[()]

    # Squeeze out size-1 dimensions MATLAB often adds
    if isinstance(raw, np.ndarray) and raw.ndim > 1:
        # Check if it looks like a reference array
        flat_items = list(raw.flat)
        if flat_items and isinstance(flat_items[0], h5py.Reference):
            result = []
            for ref in flat_items:
                try:
                    deref = h5file[ref]
                    if isinstance(deref, h5py.Dataset):
                        arr = np.array(deref[()]).ravel().astype(np.float32)
                    else:
                        arr = np.array([], dtype=np.float32)
                    result.append(arr)
                except Exception:
                    result.append(np.array([], dtype=np.float32))
            return result

    # Plain numeric array
    return raw


def _mat_value_to_list(val, path_str: str) -> list:
    """
    Convert a raw value extracted from a .mat struct into a list of
    1-D float32 spike-time arrays.

    Handles:
      - cell array of vectors  → object ndarray
      - struct array with .spks/.t etc.
      - 2-D matrix [units × spikes], NaN-padded
      - 1-D vector (single unit)
    """
    # h5py returns transposed arrays (col-major) — transpose back
    if isinstance(val, np.ndarray) and val.ndim == 2:
        if val.shape[0] > val.shape[1]:   # probably [spikes × units], transpose
            val = val.T

    # Object array (cell array) — each element is one unit
    if isinstance(val, np.ndarray) and val.dtype == object:
        result = []
        for item in val.flat:
            arr = np.asarray(item, dtype=np.float32).ravel()
            result.append(arr)
        return result

    val = np.asarray(val, dtype=np.float32)

    # 2-D → rows are units, NaN-padded
    if val.ndim == 2:
        result = []
        for row in val:
            st = row[~np.isnan(row)]
            result.append(st)
        return result

    # 1-D → single unit
    if val.ndim == 1:
        return [val[~np.isnan(val)]]

    raise ValueError(f"Unexpected spiketimes shape at '{path_str}': {val.shape}")


def load_stat(path: str) -> list:
    stat = np.load(path, allow_pickle=True)
    return list(stat)


def load_iscell(path: str) -> np.ndarray:
    return np.load(path, allow_pickle=True)  # [N x 2]


def load_ops(path: str) -> dict:
    raw = np.load(path, allow_pickle=True)
    if raw.ndim == 0:
        return raw.item()
    return dict(raw)


def compute_traces(spiketimes: list,
                   roi_indices: list,
                   kern: np.ndarray,
                   n_frames: int,
                   fps: float,
                   global_scale: bool = True,
                   clip_pct: float = 99.0) -> np.ndarray:
    """
    Convolve spike trains with GECI kernel.
    roi_indices: which entries of spiketimes correspond to iscell==1.
    Returns traces [n_rois x n_frames] float32, range [0, 1].
    """
    dt      = 1.0 / fps
    t_edges = np.arange(0, (n_frames + 1) * dt, dt)[:n_frames + 1]
    n_keep  = len(roi_indices)
    traces  = np.zeros((n_keep, n_frames), dtype=np.float32)

    for k, roi_k in enumerate(roi_indices):
        if roi_k >= len(spiketimes):
            continue
        st = spiketimes[roi_k]
        if len(st) == 0:
            continue
        counts = np.histogram(st, bins=t_edges)[0].astype(np.float32)
        conv   = fftconvolve(counts, kern, mode='same')
        traces[k] = conv[:n_frames]

    traces = np.clip(traces, 0, None)

    if global_scale:
        gmax = traces.max()
        if gmax > 0:
            traces /= gmax
    else:
        for k in range(n_keep):
            m = traces[k].max()
            if m > 0:
                traces[k] /= m

    if clip_pct < 100:
        positive = traces[traces > 0]
        if len(positive):
            vmax = np.percentile(positive, clip_pct)
            if vmax > 0:
                traces = np.clip(traces / vmax, 0, 1)

    return np.clip(traces, 0, 1)


def render_video(mean_im:     np.ndarray,
                 stat:        list,
                 iscell:      np.ndarray,
                 spiketimes:  list,
                 fps:         float,
                 tau_rise:    float,
                 tau_decay:   float,
                 output_path: str,
                 duration_sec:   float = 0,
                 n_frames_override: int = 0,
                 playback_speed: float = 2.0,
                 base_contrast: tuple = (0.1, 99.9),
                 clip_pct:    float = 99.0,
                 global_scale: bool = True,
                 overlay_color: tuple = (1.0, 1.0, 1.0),
                 color_by_roi: bool = False,
                 alpha_max:   float = 0.85,
                 quality:     int   = 8,
                 tail_margin: float = 5.0,
                 progress_cb  = None,
                 cancel_event = None):
    """
    Render the blink overlay video.

    progress_cb(fraction: float, message: str) — called periodically
    cancel_event: threading.Event — set to cancel
    """

    def prog(frac, msg):
        if progress_cb:
            progress_cb(frac, msg)

    def cancelled():
        return cancel_event is not None and cancel_event.is_set()

    prog(0.0, 'Preparing…')

    # ── ROI selection ──────────────────────────────────────────────────────
    roi_is_cell  = np.where(iscell[:, 0] == 1)[0]
    n_keep       = len(roi_is_cell)

    # ── Base image ────────────────────────────────────────────────────────
    im = mean_im.astype(np.float32)
    lo = np.percentile(im, base_contrast[0])
    hi = np.percentile(im, base_contrast[1])
    base_im = np.clip((im - lo) / max(hi - lo, 1e-6), 0, 1)  # [H x W]
    Ly, Lx   = base_im.shape

    # ── Build pixel masks ─────────────────────────────────────────────────
    prog(0.02, 'Building ROI pixel masks…')
    mask_idx = []
    for roi_k in roi_is_cell:
        s = stat[roi_k]
        ypix = np.asarray(s['ypix']).astype(int)
        xpix = np.asarray(s['xpix']).astype(int)
        ypix = np.clip(ypix, 0, Ly - 1)
        xpix = np.clip(xpix, 0, Lx - 1)
        mask_idx.append(np.ravel_multi_index((ypix, xpix), (Ly, Lx)))

    # ── Flatten all pixel indices for vectorised blending ─────────────────
    all_idx  = np.concatenate(mask_idx)                # [total_px]
    roi_of   = np.concatenate([np.full(len(m), k, dtype=np.int32)
                                for k, m in enumerate(mask_idx)])   # [total_px]

    # ── Frame count ───────────────────────────────────────────────────────
    prog(0.04, 'Determining frame count…')
    if n_frames_override > 0:
        n_frames = n_frames_override
    elif duration_sec > 0:
        n_frames = max(1, int(round(duration_sec * fps)))
    else:
        last_spike = 0.0
        for roi_k in roi_is_cell:
            if roi_k < len(spiketimes) and len(spiketimes[roi_k]):
                last_spike = max(last_spike, float(spiketimes[roi_k].max()))
        t_end    = last_spike + tail_margin * max(tau_rise, tau_decay)
        n_frames = max(1, int(round(t_end * fps)))

    # ── GECI kernel ───────────────────────────────────────────────────────
    kern = build_kernel(tau_rise, tau_decay, fps)

    # ── Convolve spikes ───────────────────────────────────────────────────
    prog(0.06, 'Convolving spikes with GECI kernel…')
    traces = compute_traces(spiketimes, list(roi_is_cell), kern,
                            n_frames, fps, global_scale, clip_pct)

    # ── Colour map ────────────────────────────────────────────────────────
    if color_by_roi:
        cmap = np.array([colorsys_hsv(k / max(n_keep, 1), 1.0, 1.0)
                         for k in range(n_keep)], dtype=np.float32)
    else:
        cmap = np.tile(np.array(overlay_color, dtype=np.float32), (n_keep, 1))

    # ── Base image as flat [H*W x 3] float32 ──────────────────────────────
    base_flat = np.stack([base_im] * 3, axis=-1).reshape(-1, 3).astype(np.float32)

    # ── Video writer ──────────────────────────────────────────────────────
    fps_out = fps * playback_speed
    writer  = imageio.get_writer(
        output_path,
        fps=fps_out,
        quality=quality,        # imageio quality 0-10
        macro_block_size=None,
        codec='libx264',
        pixelformat='yuv420p',
    )

    prog(0.08, f'Writing {n_frames} frames @ {fps_out:.1f} fps…')
    update_every = max(1, n_frames // 200)
    alpha_max_f  = np.float32(alpha_max)

    try:
        for f in range(n_frames):
            if cancelled():
                writer.close()
                raise InterruptedError('Cancelled by user.')

            if f % update_every == 0 or f == n_frames - 1:
                frac = 0.08 + 0.92 * (f / n_frames)
                prog(frac, f'Frame {f+1} / {n_frames}  ({100*f/n_frames:.0f}%)')

            # Per-ROI alphas this frame
            alphas = np.minimum(np.float32(1.0),
                                alpha_max_f * traces[:, f])   # [n_keep]

            # Per-pixel alpha and color via index lookup
            px_alpha = alphas[roi_of]                          # [total_px]
            px_color = cmap[roi_of]                            # [total_px x 3]

            frame_flat = base_flat.copy()
            active     = px_alpha > 0
            if active.any():
                ai  = all_idx[active]
                aa  = px_alpha[active, np.newaxis]             # [m x 1]
                ac  = px_color[active]                         # [m x 3]
                frame_flat[ai] = (1 - aa) * frame_flat[ai] + aa * ac

            frame_u8 = (frame_flat.reshape(Ly, Lx, 3) * 255).clip(0, 255).astype(np.uint8)
            writer.append_data(frame_u8)

        writer.close()
        prog(1.0, 'Done!')

    except Exception:
        try:
            writer.close()
        except Exception:
            pass
        raise


def colorsys_hsv(h, s, v):
    """HSV -> RGB, all in [0,1]. Avoids importing colorsys."""
    if s == 0:
        return (v, v, v)
    i = int(h * 6)
    f = h * 6 - i
    p, q, t = v*(1-s), v*(1-f*s), v*(1-(1-f)*s)
    return [(v,t,p),(q,v,p),(p,v,t),(p,q,v),(t,p,v),(v,p,q)][i % 6]


