DARK_BG   = '#0d0f14'
PANEL_BG  = '#13161e'
FIELD_BG  = '#1a1e2a'
BORDER    = '#2e3347'
ACCENT    = '#4af0b0'
ACCENT2   = '#5b8fff'
TEXT      = '#d8dce8'
TEXT2     = '#7c84a0'
WARN      = '#f0a84a'
DANGER    = '#f05b5b'
BTN_BG    = '#222736'

# Button color hierarchy
# Primary action (Generate MP4, Save)  — bright green, black text
BTN_PRIMARY_BG  = '#22c97a'
BTN_PRIMARY_FG  = '#000000'
BTN_PRIMARY_ABG = '#2ee88a'
# Secondary action (Preview, Apply W/L) — blue, white text
BTN_SECONDARY_BG  = '#1a5f9e'
BTN_SECONDARY_FG  = '#ffffff'
BTN_SECONDARY_ABG = '#2070b8'
# Utility (Browse, Reset, Advanced, Use spks.npy, Cancel in dialog)
# — subtle dark, light text, clearly distinct from primary/secondary
BTN_UTIL_BG  = '#2e3347'
BTN_UTIL_FG  = '#c8ccd8'
BTN_UTIL_ABG = '#3a4060'

MONO_FONT = ('Courier', 10)
UI_FONT   = ('Helvetica', 10)
LBL_FONT  = ('Helvetica', 9)


def mk_button(parent, text, bg, fg, abg=None, afg=None, font=None,
              command=None, state='normal', padx=8, pady=4, **kw):
    """
    Label-based button — macOS respects bg/fg on tk.Label but ignores them
    on tk.Button.  This gives us full color control on all platforms.
    """
    if abg is None:
        abg = bg
    if afg is None:
        afg = fg
    if font is None:
        font = LBL_FONT

    lbl = tk.Label(parent, text=text, bg=bg, fg=fg, font=font,
                   padx=padx, pady=pady, cursor='hand2',
                   relief='flat', **kw)

    # Store state so we can enable/disable
    lbl._btn_state   = state
    lbl._btn_bg      = bg
    lbl._btn_fg      = fg
    lbl._btn_abg     = abg
    lbl._btn_afg     = afg
    lbl._btn_command = command

    def _enter(e):
        if lbl._btn_state == 'normal':
            lbl.config(bg=abg, fg=afg)

    def _leave(e):
        if lbl._btn_state == 'normal':
            lbl.config(bg=bg, fg=fg)

    def _click(e):
        if lbl._btn_state == 'normal' and lbl._btn_command:
            lbl._btn_command()

    lbl.bind('<Enter>',          _enter)
    lbl.bind('<Leave>',          _leave)
    lbl.bind('<Button-1>',       _click)

    # Patch .config so callers can change state/bg/fg via .config(state=...)
    _orig_config = lbl.config

    def _patched_config(**opts):
        if 'state' in opts:
            lbl._btn_state = opts.pop('state')
            if lbl._btn_state == 'disabled':
                lbl.config(bg=BORDER, fg=TEXT2)
            else:
                lbl.config(bg=lbl._btn_bg, fg=lbl._btn_fg)
        if 'bg' in opts:
            lbl._btn_bg = opts['bg']
        if 'fg' in opts:
            lbl._btn_fg = opts['fg']
        if 'highlightbackground' in opts:
            pass   # silently ignore — not needed for Label
        if 'highlightthickness' in opts:
            lbl.config(relief='flat' if opts.pop('highlightthickness') == 0
                       else 'solid')
            return
        if opts:
            _orig_config(**opts)

    lbl.config = _patched_config

    if state == 'disabled':
        lbl.config(bg=BORDER, fg=TEXT2, cursor='')

    return lbl


class FileRow(tk.Frame):
    """A label + Browse button + status indicator row."""
    def __init__(self, parent, label, filetypes, callback, **kw):
        super().__init__(parent, bg=PANEL_BG, **kw)
        self._cb = callback

        tk.Label(self, text=label, fg=TEXT2, bg=PANEL_BG,
                 font=LBL_FONT, width=16, anchor='w').pack(side='left')

        self.status = tk.Label(self, text='○', fg=TEXT2, bg=PANEL_BG,
                               font=MONO_FONT, width=2)
        self.status.pack(side='left')

        self.path_var = tk.StringVar(value='')
        self.entry = tk.Entry(self, textvariable=self.path_var,
                              bg=FIELD_BG, fg=TEXT, insertbackground=TEXT,
                              relief='flat', font=MONO_FONT, width=28)
        self.entry.pack(side='left', fill='x', expand=True, padx=(4, 4))

        self.filetypes = filetypes
        mk_button(self, text='Browse…', bg=BTN_UTIL_BG, fg=BTN_UTIL_FG,
                  abg=BTN_UTIL_ABG, afg=BTN_UTIL_FG,
                  padx=6, command=self._browse).pack(side='left')

    def _browse(self):
        p = filedialog.askopenfilename(filetypes=self.filetypes)
        if p:
            self.path_var.set(p)
            self.set_status('ok')
            if self._cb:
                self._cb(p)

    def get(self):
        return self.path_var.get()

    def set_status(self, state):
        colours = {'ok': ACCENT, 'err': DANGER, 'idle': TEXT2}
        symbols = {'ok': '●', 'err': '✗', 'idle': '○'}
        self.status.config(fg=colours.get(state, TEXT2),
                           text=symbols.get(state, '○'))


class ParamRow(tk.Frame):
    """Label + entry on one row."""
    def __init__(self, parent, label, default='', width=10, **kw):
        super().__init__(parent, bg=PANEL_BG, **kw)
        tk.Label(self, text=label, fg=TEXT2, bg=PANEL_BG,
                 font=LBL_FONT, width=22, anchor='w').pack(side='left')
        self.var = tk.StringVar(value=str(default))
        tk.Entry(self, textvariable=self.var, bg=FIELD_BG, fg=TEXT,
                 insertbackground=TEXT, relief='flat',
                 font=MONO_FONT, width=width).pack(side='left', padx=4)

    def get(self):
        return self.var.get()

    def get_float(self, default=None):
        try:
            return float(self.var.get())
        except ValueError:
            return default

    def get_int(self, default=None):
        try:
            return int(self.var.get())
        except ValueError:
            return default


class SliderRow(tk.Frame):
    def __init__(self, parent, label, from_, to, default, resolution=0.01,
                 on_change=None, **kw):
        super().__init__(parent, bg=PANEL_BG, **kw)
        self._on_change = on_change
        self._from = from_
        self._to   = to
        tk.Label(self, text=label, fg=TEXT2, bg=PANEL_BG,
                 font=LBL_FONT, width=18, anchor='w').pack(side='left')
        self.var = tk.DoubleVar(value=default)

        # Numeric entry box — right side, type to set exact value
        self._entry_var = tk.StringVar(value=f'{default:.2f}')
        entry = tk.Entry(self, textvariable=self._entry_var,
                         bg=FIELD_BG, fg=ACCENT, insertbackground=ACCENT,
                         relief='flat', font=MONO_FONT, width=6,
                         justify='right', highlightthickness=1,
                         highlightbackground=BORDER, highlightcolor=ACCENT)
        entry.pack(side='right', padx=(4, 0))
        entry.bind('<Return>',   self._entry_commit)
        entry.bind('<FocusOut>', self._entry_commit)

        # Use ttk.Scale — macOS ignores bg on tk.Scale, ttk respects styling
        style_name = f'Slider{id(self)}.Horizontal.TScale'
        style = ttk.Style()
        style.theme_use('default')
        style.configure(style_name,
                        background=PANEL_BG,
                        troughcolor=FIELD_BG,
                        troughrelief='flat',
                        sliderlength=12,
                        sliderrelief='flat')
        self._scale = ttk.Scale(self, variable=self.var, from_=from_, to=to,
                                orient='horizontal', style=style_name,
                                command=self._slider_moved)
        self._scale.pack(side='left', fill='x', expand=True)
        self._after_id = None

    def _slider_moved(self, val):
        """Slider moved → update entry box."""
        self._entry_var.set(f'{float(val):.2f}')
        if self._on_change:
            if self._after_id:
                self.after_cancel(self._after_id)
            self._after_id = self.after(80, self._on_change)

    def _entry_commit(self, event=None):
        """Entry box edited → clamp and push to slider."""
        try:
            v = float(self._entry_var.get())
            v = max(self._from, min(self._to, v))
            self.var.set(v)
            self._entry_var.set(f'{v:.2f}')
            if self._on_change:
                if self._after_id:
                    self.after_cancel(self._after_id)
                self._after_id = self.after(10, self._on_change)
        except ValueError:
            # Restore last valid value
            self._entry_var.set(f'{self.var.get():.2f}')

    # Keep old name so existing code calling _update still works
    def _update(self, val=None):
        if val is None:
            val = self.var.get()
        self._entry_var.set(f'{float(val):.2f}')

    def get(self):
        return self.var.get()


class SectionLabel(tk.Label):
    def __init__(self, parent, text, **kw):
        super().__init__(parent, text=text.upper(), fg=TEXT2, bg=PANEL_BG,
                         font=('Helvetica', 8, 'bold'), anchor='w', **kw)


# ── Embedded app icon (blink.png, base64-encoded PNG) ─────────────────────────
ICON_B64 = ""

# Blinky animation — two frames: eyes open and eyes closed
BLINKY_OPEN   = ""
BLINKY_CLOSED = ""


