    def _build_ui(self):
        self.columnconfigure(1, weight=1)
        self.rowconfigure(0, weight=1)

        # Sidebar — fixed width, scrollable internally
        sidebar_outer = tk.Frame(self, bg=PANEL_BG)
        sidebar_outer.grid(row=0, column=0, sticky='nsew')
        sidebar_outer.grid_propagate(False)
        sidebar_outer.configure(width=360)
        sidebar_outer.rowconfigure(0, weight=1)
        sidebar_outer.columnconfigure(0, weight=1)

        preview_col = tk.Frame(self, bg=DARK_BG)
        preview_col.grid(row=0, column=1, sticky='nsew')
        preview_col.rowconfigure(1, weight=1)
        preview_col.columnconfigure(0, weight=1)

        self._build_sidebar(sidebar_outer)
        self._build_preview(preview_col)

