    def _setup_drag_drop(self):
        """Enable drag-and-drop if tkinterdnd2 is installed."""
        try:
            from tkinterdnd2 import DND_FILES
            self._drop_frame.drop_target_register(DND_FILES)
            self._drop_frame.dnd_bind('<<Drop>>', self._on_folder_drop)
        except Exception:
            pass   # tkinterdnd2 not installed — Browse button still works

    def _on_folder_drop(self, event):
        """Handle a drag-and-drop event from tkinterdnd2."""
        path = event.data.strip().strip('{}')   # strip braces on Mac/Windows
        if os.path.isdir(path):
            self._load_suite2p_folder(path)
        else:
            # Maybe they dropped a file inside the folder — use its parent
            parent = os.path.dirname(path)
            if os.path.isdir(parent):
                self._load_suite2p_folder(parent)

    def _browse_folder(self):
        folder = filedialog.askdirectory(title='Select Suite2p output folder')
        if folder:
            self._load_suite2p_folder(folder)

    def _load_suite2p_folder(self, folder):
        """
        Given a Suite2p output folder (or a plane subfolder), find and load:
          ops.npy, stat.npy, iscell.npy
        Searches the given folder, then one level down (plane0/, plane1/, etc.)
        """
        # Reset all state so old data never bleeds into a new session
        self._stat       = None
        self._iscell     = None
        self._ops        = None
        self._spiketimes = None
        self._mean_im    = None
        self._mean_disp  = None
        self._canvas.delete('all')

        self._log_msg(f'Scanning folder: {folder}')
        found = {}

        # Search root then subdirs
        search_dirs = [folder] + [
            os.path.join(folder, d)
            for d in sorted(os.listdir(folder))
            if os.path.isdir(os.path.join(folder, d))
        ]

        for d in search_dirs:
            for fname in ('ops.npy', 'stat.npy', 'iscell.npy'):
                if fname not in found:
                    candidate = os.path.join(d, fname)
                    if os.path.isfile(candidate):
                        found[fname] = candidate

        # Update drop zone label
        short = os.path.basename(folder)
        self._drop_lbl.config(
            text=f'📂  {short}\n{len(found)}/3 files found',
            fg=ACCENT if len(found) == 3 else WARN)

        # Load each found file
        for fname, dot in self._file_status.items():
            if fname in found:
                dot.config(text='●', fg=ACCENT)
            else:
                dot.config(text='✗', fg=DANGER)
                self._log_msg(f'Not found: {fname}', 'err')

        if 'ops.npy' in found:
            self._on_ops_load(found['ops.npy'])
        if 'stat.npy' in found:
            self._on_stat_load(found['stat.npy'])
        if 'iscell.npy' in found:
            self._on_iscell_load(found['iscell.npy'])

        # Also look for spks.npy and spiketimes.npy in same dirs
        for d in search_dirs:
            spks_path = os.path.join(d, 'spks.npy')
            if os.path.isfile(spks_path):
                self._spks_path = spks_path
                self._spk_info.config(
                    text=f'spks.npy found — click "Use spks.npy" to load',
                    fg=WARN)
                self._log_msg('spks.npy found in folder', 'ok')
                break
        for d in search_dirs:
            for spk_name in ('spiketimes.npy', 'spiketimes.mat'):
                st_path = os.path.join(d, spk_name)
                if os.path.isfile(st_path):
                    self._on_spk_load(st_path)
                    break
            else:
                continue
            break

    def _build_preview(self, parent):
        # Toolbar
        toolbar = tk.Frame(parent, bg=PANEL_BG)
        toolbar.grid(row=0, column=0, sticky='ew', pady=(0,1))
        tk.Label(toolbar, text='Mean projection preview',
                 fg=TEXT2, bg=PANEL_BG, font=LBL_FONT).pack(side='left', padx=10)

        # Canvas
        self._canvas = tk.Canvas(parent, bg='#080a0d', highlightthickness=0)
        self._canvas.grid(row=1, column=0, sticky='nsew')
        parent.rowconfigure(1, weight=1)

        # Progress bar
        prog_frame = tk.Frame(parent, bg=DARK_BG)
        prog_frame.grid(row=2, column=0, sticky='ew', pady=(2,0))
        self._prog_bar = ttk.Progressbar(prog_frame, mode='determinate', length=300)
        self._prog_bar.pack(side='left', fill='x', expand=True, padx=8, pady=4)
        self._prog_lbl = tk.Label(prog_frame, text='', fg=TEXT2, bg=DARK_BG,
                                  font=MONO_FONT)
        self._prog_lbl.pack(side='left', padx=4)
        self._btn_cancel = mk_button(prog_frame, text='Cancel',
                                     bg=DANGER, fg='white',
                                     abg='#d94040', afg='white',
                                     padx=6, state='disabled',
                                     command=self._cancel)
        self._btn_cancel.pack(side='right', padx=8, pady=2)

        # Log
        log_frame = tk.Frame(parent, bg='#080a0d')
        log_frame.grid(row=3, column=0, sticky='ew')
        self._log = tk.Text(log_frame, height=5, bg='#080a0d', fg=ACCENT,
                            font=MONO_FONT, relief='flat',
                            state='disabled', wrap='word')
        self._log.pack(fill='both', expand=True, padx=6, pady=4)

        # Status bar
        self._status_var = tk.StringVar(value='● Waiting for files')
        tk.Label(parent, textvariable=self._status_var,
                 fg=TEXT2, bg=DARK_BG, font=MONO_FONT,
                 anchor='w').grid(row=4, column=0, sticky='ew', padx=8, pady=2)

    # ── File load callbacks ────────────────────────────────────────────────

    def _on_ops_load(self, path):
        try:
            self._ops = load_ops(path)
            fps = float(self._ops.get('fs', 22.93))
            self._fps_var.set(f'{fps:.3f} Hz')
            if 'meanImg' in self._ops:
                self._mean_im   = np.array(self._ops['meanImg'], dtype=np.float32)
                self._mean_disp = self._mean_im.copy()
                self._refresh_preview()
                self._log_msg(f'ops.meanImg loaded  '
                              f'({self._mean_im.shape[1]}×{self._mean_im.shape[0]} px)')
            self._file_status['ops.npy'].config(text='●', fg=ACCENT)
            self._log_msg(f'ops.npy loaded  fps={fps:.3f}', 'ok')
            self._check_ready()
        except Exception as e:
            self._file_status['ops.npy'].config(text='✗', fg=DANGER)
            self._log_msg(f'ops.npy error: {e}', 'err')

    def _on_stat_load(self, path):
        try:
            self._stat = load_stat(path)
            self._file_status['stat.npy'].config(text='●', fg=ACCENT)
            self._log_msg(f'stat.npy loaded  {len(self._stat)} ROIs', 'ok')
            self._check_ready()
        except Exception as e:
            self._file_status['stat.npy'].config(text='✗', fg=DANGER)
            self._log_msg(f'stat.npy error: {e}', 'err')

    def _on_iscell_load(self, path):
        try:
            self._iscell = load_iscell(path)
            n_cell = int((self._iscell[:, 0] == 1).sum())
            self._file_status['iscell.npy'].config(text='●', fg=ACCENT)
            self._log_msg(f'iscell.npy loaded  {n_cell} / {len(self._iscell)} cells', 'ok')
            self._check_ready()
        except Exception as e:
            self._file_status['iscell.npy'].config(text='✗', fg=DANGER)
            self._log_msg(f'iscell.npy error: {e}', 'err')

    def _on_spk_load(self, path):
        try:
            self._spiketimes = load_spiketimes(path)
            n = len(self._spiketimes)
            self._spk_info.config(text=f'✓  {n} units found', fg=ACCENT)
            self._row_spk.set_status('ok')
            self._log_msg(f'spiketimes.npy loaded  {n} units', 'ok')
            self._check_ready()
        except Exception as e:
            self._row_spk.set_status('err')
            self._spk_info.config(text=str(e)[:60], fg=DANGER)
            self._log_msg(f'spiketimes error: {e}', 'err')

    def _load_spks_npy(self):
        """
        Load spks.npy (Suite2p deconvolved trace [N_all_rois × T_frames]),
        filter to iscell==1 rows only, binarize at threshold, convert to
        spike-time lists in seconds.
        """
        # Let user browse if folder scan didn't find it
        path = self._spks_path
        if path is None or not os.path.isfile(path):
            path = filedialog.askopenfilename(
                title='Select spks.npy',
                filetypes=[('NPY', '*.npy'), ('All', '*.*')])
            if not path:
                return
            self._spks_path = path

        if self._iscell is None:
            messagebox.showwarning('iscell missing',
                                   'Load iscell.npy first so spks can be filtered.')
            return

        try:
            thresh = float(self._spks_thresh_var.get())
        except ValueError:
            thresh = 0.5

        try:
            self._spiketimes = self._binarize_spks(path, thresh)
            n = len(self._spiketimes)
            self._spk_info.config(
                text=f'✓  {n} units  (spks.npy, thresh={thresh:.2f})',
                fg=ACCENT)
            self._row_spk.set_status('ok')
            self._log_msg(
                f'spks.npy binarized: {n} units, threshold={thresh:.2f}', 'ok')
            # Log how many units had at least one spike
            n_active = sum(1 for st in self._spiketimes if len(st) > 0)
            self._log_msg(f'  {n_active}/{n} units have spikes above threshold')
            self._check_ready()
        except Exception as e:
            import traceback
            self._spk_info.config(text=str(e)[:70], fg=DANGER)
            self._log_msg(f'spks.npy error: {e}', 'err')
            self._log_msg(traceback.format_exc()[-200:], 'err')

    def _binarize_spks(self, path: str, threshold: float) -> list:
        """
        Convert Suite2p spks.npy to a list of spike-time arrays (seconds).

        spks.npy shape: [N_all_rois × T_frames]
          - Values are in arbitrary units (e.g. 0–5000+)
          - Each ROI is normalised to [0, 1] before thresholding so the
            threshold is always a fraction of each ROI's own peak activity
          - Only iscell==1 rows are kept
          - Spike times = frames where normalised spks[k, t] >= threshold
          - Converted to seconds using ops.fs
        """
        spks = np.load(path, allow_pickle=True)

        if spks.ndim == 0:
            spks = spks.item()
        if isinstance(spks, dict):
            for key in ('spks', 'S', 'spike_matrix'):
                if key in spks:
                    spks = spks[key]
                    break

        spks = np.array(spks, dtype=np.float32)

        if spks.ndim == 1:
            spks = spks[np.newaxis, :]

        n_rois, n_frames = spks.shape
        self._log_msg(f'spks.npy shape: {n_rois} ROIs × {n_frames} frames')

        # ── Per-ROI normalisation to [0, 1] ──────────────────────────────
        # This makes the threshold scale-invariant regardless of AU range
        row_max = spks.max(axis=1, keepdims=True)   # [N × 1]
        row_max = np.where(row_max > 0, row_max, 1.0)  # avoid divide-by-zero
        spks = spks / row_max
        self._log_msg(f'Normalised per-ROI to [0,1]. Threshold={threshold:.3f}')

        # Get fps
        fps = 22.93
        fps_str = self._fps_var.get().replace('Hz', '').strip()
        try:
            fps = float(fps_str)
        except ValueError:
            pass

        # Filter to iscell==1 rows
        cell_mask = self._iscell[:, 0] == 1
        n_all = len(cell_mask)

        if n_rois != n_all:
            self._log_msg(
                f'spks has {n_rois} rows, iscell has {n_all} — '
                f'using min({n_rois},{n_all}) rows', 'warn')
            use = min(n_rois, n_all)
            cell_mask = cell_mask[:use]
            spks = spks[:use]

        cell_rows = np.where(cell_mask)[0]
        dt = 1.0 / fps

        spiketimes = []
        for row_idx in cell_rows:
            frames = np.where(spks[row_idx] >= threshold)[0]
            spiketimes.append((frames * dt).astype(np.float32))

        return spiketimes

    def _on_img_load(self, path):
        try:
            ext = Path(path).suffix.lower()
            if ext == '.npy':
                raw = np.load(path, allow_pickle=True)
                if raw.ndim == 0:
                    raw = raw.item()
                if isinstance(raw, dict):
                    raw = raw.get('meanImg', raw)
                im = np.array(raw, dtype=np.float32)
            else:
                from PIL import Image as PILImage
                pil = PILImage.open(path).convert('L')
                im  = np.array(pil, dtype=np.float32)
            self._mean_im   = im
            self._mean_disp = im.copy()
            self._refresh_preview()
            self._row_img.set_status('ok')
            self._log_msg(f'Mean image override: {Path(path).name}  '
                          f'({im.shape[1]}×{im.shape[0]})', 'ok')
        except Exception as e:
            self._row_img.set_status('err')
            self._log_msg(f'Image load error: {e}', 'err')

    # ── W/L ───────────────────────────────────────────────────────────────

    def _apply_wl_silent(self):
        """Called automatically on every slider move (debounced). No log entry."""
        if self._mean_im is None:
            return
        im = self._mean_im.copy()
        # 1. Percentile clip / stretch
        lo = np.percentile(im, self._sl_lo.get())
        hi = np.percentile(im, self._sl_hi.get())
        im = (im - lo) / max(hi - lo, 1e-6)
        im = np.clip(im, 0, 1)
        # 2. Gamma (luminance curve) — applied before linear contrast/brightness
        gamma = max(self._sl_gamma.get(), 0.01)
        im = np.power(im, gamma)
        # 3. Linear contrast + brightness
        im = im * self._sl_contrast.get() + self._sl_bright.get() / 100.0
        self._mean_disp = np.clip(im, 0, 1)
        self._refresh_preview()

    def _apply_wl(self):
        """Called by the Apply button — same logic but logs the action."""
        self._apply_wl_silent()
        if self._mean_im is not None:
            self._log_msg(
                f'W/L applied: bright={self._sl_bright.get():.1f}  '
                f'contrast={self._sl_contrast.get():.2f}×  '
                f'gamma={self._sl_gamma.get():.2f}  '
                f'lo={self._sl_lo.get():.2f}%  hi={self._sl_hi.get():.2f}%'
            )

    def _reset_wl(self):
        for sl, val in [(self._sl_bright, 0), (self._sl_contrast, 1.0),
                        (self._sl_gamma, 1.0),
                        (self._sl_lo, 1.0), (self._sl_hi, 99.9)]:
            sl.var.set(val)
            sl._update(val)
        self._apply_wl_silent()
        self._log_msg('W/L reset.')

    def _refresh_preview(self):
        if self._mean_disp is None:
            return
        im  = self._mean_disp
        lo  = np.percentile(im, 1)
        hi  = np.percentile(im, 99.9)
        im8 = np.clip((im - lo) / max(hi - lo, 1e-6) * 255, 0, 255).astype(np.uint8)

        # Convert to RGB so we can paint coloured ROI overlays
        rgb = np.stack([im8, im8, im8], axis=-1)

        # Draw ROI outlines if toggled on and data is available
        if (getattr(self, '_show_rois_var', None) and self._show_rois_var.get()
                and self._stat is not None and self._iscell is not None):
            try:
                Ly, Lx = im8.shape
                alpha  = float(self._sl_alpha.get())
                r_col  = float(self._sl_r.get())
                g_col  = float(self._sl_g.get())
                b_col  = float(self._sl_b.get())
                color_by_roi = self._color_mode.get() == 'roi'
                roi_is_cell  = np.where(self._iscell[:, 0] == 1)[0]
                n_keep = len(roi_is_cell)

                for k, roi_idx in enumerate(roi_is_cell):
                    s = self._stat[roi_idx]
                    ypix = np.clip(np.asarray(s['ypix']).astype(int), 0, Ly-1)
                    xpix = np.clip(np.asarray(s['xpix']).astype(int), 0, Lx-1)
                    if color_by_roi:
                        rc, gc, bc = colorsys_hsv(k / max(n_keep, 1), 1.0, 1.0)
                    else:
                        rc, gc, bc = r_col, g_col, b_col
                    # Alpha-blend ROI pixels
                    for ch, c in enumerate([rc, gc, bc]):
                        rgb[ypix, xpix, ch] = np.clip(
                            rgb[ypix, xpix, ch] * (1 - alpha) + c * 255 * alpha,
                            0, 255).astype(np.uint8)
            except Exception:
                pass   # silently skip if stat/iscell not fully loaded

        cw = self._canvas.winfo_width()  or 600
        ch = self._canvas.winfo_height() or 500
        pil = Image.fromarray(rgb, mode='RGB')
        pil.thumbnail((cw, ch), Image.LANCZOS)
        self._tk_img = ImageTk.PhotoImage(pil)
        self._canvas.delete('all')
        self._canvas.create_image(cw//2, ch//2, image=self._tk_img, anchor='center')

    # ── Readiness ─────────────────────────────────────────────────────────

    def _check_ready(self):
        have_fall  = self._stat is not None and self._iscell is not None and self._ops is not None
        have_spk   = self._spiketimes is not None
        have_img   = self._mean_im is not None
        ready = have_fall and have_spk and have_img
        state = 'normal' if ready else 'disabled'
        self._btn_preview.config(state=state)
        self._btn_render.config(state=state)
        if ready:
            self._status_var.set('● Ready to render')
        elif have_fall and have_img and not have_spk:
            self._status_var.set('● Waiting for spiketimes / spks.npy')
        elif have_fall and not have_img:
            self._status_var.set('● Waiting for mean image (ops.meanImg missing?)')
        elif have_spk and not have_fall:
            self._status_var.set('● Waiting for ops / stat / iscell')
        else:
            self._status_var.set('● Waiting for files')

    # ── Gather opts ────────────────────────────────────────────────────────

    def _browse_output_folder(self):
        folder = filedialog.askdirectory(title='Select output folder')
        if folder:
            self._out_folder_var.set(folder)
            self._out_lbl.config(text=f'📁 {folder}', fg=ACCENT)

    def _get_output_path(self, suffix=''):
        """Build output path from folder + auto timestamp filename."""
        import datetime
        folder = self._out_folder_var.get().strip()
        if not folder or not os.path.isdir(folder):
            folder = os.path.expanduser('~')
        ts   = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
        name = f'roi_blink{suffix}_{ts}.mp4'
        return os.path.join(folder, name)

    def _gather_opts(self, preview_dur=None):
        fps_str = self._fps_var.get().replace('Hz','').strip()
        try:
            fps = float(fps_str)
        except ValueError:
            fps = 22.93

        suffix = f'_preview{preview_dur:.0f}s' if preview_dur else ''
        out = self._get_output_path(suffix)
        self._out_lbl.config(text=f'→ {os.path.basename(out)}', fg=TEXT2)

        return dict(
            fps          = fps,
            tau_rise     = self._tau_rise.get_float(0.07),
            tau_decay    = self._tau_decay.get_float(0.70),
            duration_sec = preview_dur if preview_dur is not None
                           else (self._dur_sec.get_float(0) or 0),
            n_frames_override = 0 if preview_dur else (self._n_frames.get_int(0) or 0),
            playback_speed = self._speed.get_float(2.0),
            output_path  = out,
            overlay_color = (self._sl_r.get(), self._sl_g.get(), self._sl_b.get()),
            color_by_roi = self._color_mode.get() == 'roi',
            alpha_max    = self._sl_alpha.get(),
            base_contrast = (self._sl_lo.get(), self._sl_hi.get()),
            clip_pct     = getattr(self, '_adv_clip', 99.0),
            global_scale = getattr(self, '_adv_global', True),
            quality      = getattr(self, '_adv_quality', 8),
            tail_margin  = getattr(self, '_adv_tail', 5.0),
        )

    # ── Render in background thread ────────────────────────────────────────

    def _start_render(self, opts):
        self._cancel_event.clear()
        self._btn_cancel.config(state='normal')
        self._btn_preview.config(state='disabled')
        self._btn_render.config(state='disabled')
        self._prog_bar['value'] = 0
        self._blinky_start()   # start animation

        mean_im = self._mean_disp if self._mean_disp is not None else self._mean_im

        def worker():
            try:
                render_video(
                    mean_im      = mean_im,
                    stat         = self._stat,
                    iscell       = self._iscell,
                    spiketimes   = self._spiketimes,
                    progress_cb  = self._progress_cb,
                    cancel_event = self._cancel_event,
                    **opts,
                )
                self._q.put(('done', opts['output_path']))
            except InterruptedError:
                self._q.put(('cancelled', ''))
            except Exception as e:
                self._q.put(('error', str(e)))

        threading.Thread(target=worker, daemon=True).start()

    def _progress_cb(self, frac, msg):
        self._q.put(('progress', frac, msg))

    def _run_preview(self):
        try:
            dur = float(self._prev_dur.get())
        except ValueError:
            dur = 5.0
        opts = self._gather_opts(preview_dur=dur)
        self._log_msg(f'Preview ({dur:.0f} s) → {opts["output_path"]}')
        self._start_render(opts)

    def _run_render(self):
        opts = self._gather_opts()
        self._log_msg(f'Rendering → {opts["output_path"]}')
        self._start_render(opts)

    def _cancel(self):
        self._cancel_event.set()
        self._log_msg('Cancelling…', 'warn')

    # ── Blinky rendering animation ─────────────────────────────────────────

    def _blinky_start(self):
        """Load both blinky frames and start bouncing animation on the canvas."""
        try:
            import base64, io
            cw = self._canvas.winfo_width()  or 600
            ch = self._canvas.winfo_height() or 500
            bh = max(80, ch // 4)

            frames = []
            for b64 in (BLINKY_OPEN, BLINKY_CLOSED):
                pil = Image.open(io.BytesIO(base64.b64decode(b64))).convert('RGBA')
                bw  = int(pil.width * bh / pil.height)
                pil = pil.resize((bw, bh), Image.LANCZOS)
                frames.append(pil)

            self._blinky_frames = frames   # [open, closed]
            self._blinky_bw     = frames[0].width
            self._blinky_bh     = bh
            self._blinky_x      = float(cw // 2)
            self._blinky_vx     = 4.0
            self._blinky_tick_n = 0
            # Pre-render PhotoImages (rebuilt on resize — just start with these)
            self._blinky_photos = [ImageTk.PhotoImage(f) for f in frames]
        except Exception as e:
            self._blinky_frames = None
            self._log_msg(f'Blinky load error: {e}', 'warn')
        self._blinky_tick()

    def _blinky_stop(self):
        if self._blinky_after:
            self.after_cancel(self._blinky_after)
            self._blinky_after = None
        self._canvas.delete('blinky')
        self._canvas.delete('blinky_txt')
        self._refresh_preview()

    def _blinky_tick(self):
        """One animation tick: bounce + alternate frames at 0.5 Hz."""
        import math

        try:
            cw = self._canvas.winfo_width()  or 600
            ch = self._canvas.winfo_height() or 500
            n  = self._blinky_tick_n
            bw = self._blinky_bw
            bh = self._blinky_bh

            # ── Pick frame ──────────────────────────────────────────────
            # 2 Hz blink: 13 tick cycle at 40ms/tick ≈ 0.5 seconds
            # eyes open for 10 ticks (~0.4s), closed for 3 ticks (~0.12s)
            cycle = n % 13
            frame_idx = 1 if cycle >= 10 else 0   # 1 = closed, 0 = open

            # ── Bounce ──────────────────────────────────────────────────
            self._blinky_x += self._blinky_vx
            if self._blinky_x + bw // 2 > cw - 10:
                self._blinky_x = cw - 10 - bw // 2
                self._blinky_vx = -abs(self._blinky_vx)
            if self._blinky_x - bw // 2 < 10:
                self._blinky_x = 10 + bw // 2
                self._blinky_vx =  abs(self._blinky_vx)

            # Vertical bob
            y = int(ch * 0.45) + int(14 * math.sin(n * 0.13))

            # ── Draw figure ─────────────────────────────────────────────
            if self._blinky_frames:
                photo = self._blinky_photos[frame_idx]
                self._canvas.delete('blinky')
                self._canvas.create_image(
                    int(self._blinky_x), y,
                    image=photo, anchor='center', tags='blinky')

            # ── Caption ─────────────────────────────────────────────────
            captions = [
                'Blinkifying your neurons…',
                'Blinkyfying your neurons…',
                'Blinkefiying your neurons…',
                'Blinkifying your neurons…',
            ]
            cap = captions[(n // 30) % len(captions)]
            self._canvas.delete('blinky_txt')
            self._canvas.create_text(
                cw // 2, ch - 30,
                text=cap,
                fill='#4af0b0',
                font=('Helvetica', 14, 'bold'),
                tags='blinky_txt')

            self._blinky_tick_n += 1

        except Exception:
            pass

        self._blinky_after = self.after(40, self._blinky_tick)  # 25 fps

    def _poll_queue(self):
        try:
            while True:
                msg = self._q.get_nowait()
                if msg[0] == 'progress':
                    _, frac, text = msg
                    self._prog_bar['value'] = frac * 100
                    self._prog_lbl.config(text=text)
                elif msg[0] == 'done':
                    self._prog_bar['value'] = 100
                    self._prog_lbl.config(text='Done!')
                    self._log_msg(f'Written: {msg[1]}', 'ok')
                    self._status_var.set('● Complete')
                    self._btn_cancel.config(state='disabled')
                    self._btn_preview.config(state='normal')
                    self._btn_render.config(state='normal')
                    self._blinky_stop()
                elif msg[0] == 'cancelled':
                    self._prog_lbl.config(text='Cancelled')
                    self._log_msg('Cancelled.', 'warn')
                    self._status_var.set('● Cancelled')
                    self._btn_cancel.config(state='disabled')
                    self._btn_preview.config(state='normal')
                    self._btn_render.config(state='normal')
                    self._blinky_stop()
                elif msg[0] == 'error':
                    self._prog_lbl.config(text='Error')
                    self._log_msg(f'Error: {msg[1]}', 'err')
                    self._status_var.set('● Error')
                    self._btn_cancel.config(state='disabled')
                    self._btn_preview.config(state='normal')
                    self._btn_render.config(state='normal')
                    self._blinky_stop()
                    messagebox.showerror('Render error', msg[1])
        except queue.Empty:
            pass
        self.after(80, self._poll_queue)

    # ── Log ───────────────────────────────────────────────────────────────

    def _log_msg(self, msg, level=''):
        ts = time.strftime('%H:%M:%S')
        colours = {'ok': ACCENT, 'err': DANGER, 'warn': WARN, '': TEXT2}
        self._log.config(state='normal')
        self._log.insert('end', f'[{ts}] {msg}\n')
        self._log.see('end')
        self._log.config(state='disabled')

    # ── Advanced dialog ────────────────────────────────────────────────────

    def _open_advanced(self):
        d = tk.Toplevel(self, bg=PANEL_BG)
        d.title('Advanced Parameters')
        d.resizable(False, False)
        d.geometry('420x320')

        rows = [
            ('Clip percentile', '_adv_clip',    99.0),
            ('Global scale (1=yes, 0=per-ROI)', '_adv_global', 1),
            ('Encoder quality (0–10)',  '_adv_quality', 8),
            ('Extra secs after last spike', '_adv_tail', 5.0),
            ('Base contrast low %',    '_adv_bc_lo',   0.1),
            ('Base contrast high %',   '_adv_bc_hi',   99.9),
        ]
        entries = {}
        for i, (lbl, attr, default) in enumerate(rows):
            val = getattr(self, attr, default)
            r = ParamRow(d, lbl, val)
            r.pack(fill='x', padx=16, pady=4)
            entries[attr] = r

        # Help text for tail margin
        tk.Label(d, text='When duration=0, video ends (tail × max(τ)) after last spike.',
                 fg=TEXT2, bg=PANEL_BG, font=('Helvetica', 8),
                 wraplength=380, justify='left').pack(padx=16, anchor='w')

        def save():
            for attr, r in entries.items():
                try:
                    setattr(self, attr, float(r.get()))
                except ValueError:
                    pass
            self._log_msg('Advanced parameters saved.', 'ok')
            d.destroy()

        btn_row = tk.Frame(d, bg=PANEL_BG)
        btn_row.pack(fill='x', padx=16, pady=12)
        mk_button(btn_row, text='Save',
                  bg=BTN_PRIMARY_BG, fg=BTN_PRIMARY_FG,
                  abg=BTN_PRIMARY_ABG, afg=BTN_PRIMARY_FG,
                  font=(UI_FONT[0], UI_FONT[1], 'bold'), padx=12,
                  command=save).pack(side='right', padx=(6,0))
        mk_button(btn_row, text='Cancel',
                  bg=BTN_UTIL_BG, fg=BTN_UTIL_FG,
                  abg=BTN_UTIL_ABG, afg=BTN_UTIL_FG,
                  font=UI_FONT, padx=12,
                  command=d.destroy).pack(side='right')


